import { useEffect, useState } from "react";
import axios from "axios";
import Api from "../api/Api";

export default function CreatePickupRequest() {
  const [locations, setLocations] = useState([]);
  const [search, setSearch] = useState("");
  const [selectedLocation, setSelectedLocation] = useState(null);
  const [priority, setPriority] = useState("Medium");
  const [showDropdown, setShowDropdown] = useState(false);

  const [requestCreated, setRequestCreated] = useState(false);
  const [currentStatus, setCurrentStatus] = useState("Pending");

  useEffect(() => {
    getLocations();
  }, []);

  const getLocations = async () => {
    try {
      const response = await axios.get(Api.get_All_Locations);
      setLocations(response.data);
    } catch (error) {
      console.log(error);
    }
  };

  const filteredLocations = locations.filter((item) =>
    item.location.toLowerCase().includes(search.toLowerCase())
  );

  const handleSubmit = async () => {
    try {
      if (!selectedLocation) {
        return alert("Please Select Location");
      }

      const supervisorId = localStorage.getItem("id");

      const response = await axios.post(Api.create_Emg_Req, {
        requestedBy: supervisorId,
        location: selectedLocation._id,
        priority,
      });

      alert("Emergency Request Created Successfully");

      setRequestCreated(true);
      setCurrentStatus("Pending");

      console.log(response.data);
    } catch (error) {
      console.log(error);
      alert("Failed To Create Request");
    }
  };

  const steps = [
    "Pending",
    "Accepted",
    "Scheduled",
    "Arrived",
    "Completed",
  ];

  const currentIndex = steps.indexOf(currentStatus);

  return (
    <div className="min-h-screen bg-gradient-to-br from-green-50 to-gray-100 py-8 px-4">
      <div className="max-w-md mx-auto">

        {/* Header */}

        <div className="mb-6">
          <p className="uppercase tracking-widest text-gray-500 text-xs font-bold">
            Fleet Management
          </p>

          <h1 className="text-4xl font-extrabold text-green-900 mt-2">
            Create Pickup Request
          </h1>

          <p className="text-gray-500 mt-2">
            Create emergency garbage pickup request
          </p>
        </div>

        {/* Location Card */}

        <div className="bg-white rounded-3xl shadow-lg p-5 mb-5 border">

          <div className="flex justify-between items-center mb-4">
            <h2 className="font-bold text-lg">
              📍 Pickup Location
            </h2>

            <button className="text-green-700 text-sm font-semibold">
              Use Current
            </button>
          </div>

          <div className="relative">

            <input
              type="text"
              value={search}
              placeholder="Search Location..."
              onChange={(e) => {
                setSearch(e.target.value);
                setShowDropdown(true);
              }}
              className="w-full border-2 border-gray-200 focus:border-green-600 rounded-xl px-4 py-3 outline-none"
            />

            {showDropdown && (
              <div className="absolute z-50 w-full bg-white border rounded-xl mt-2 shadow-lg max-h-60 overflow-y-auto">

                {filteredLocations.length > 0 ? (
                  filteredLocations.map((loc) => (
                    <div
                      key={loc._id}
                      onClick={() => {
                        setSelectedLocation(loc);
                        setSearch(loc.location);
                        setShowDropdown(false);
                      }}
                      className="px-4 py-3 hover:bg-green-100 cursor-pointer"
                    >
                      {loc.location}
                    </div>
                  ))
                ) : (
                  <div className="p-4 text-gray-500">
                    No Location Found
                  </div>
                )}

              </div>
            )}

          </div>

          {selectedLocation && (
            <div className="mt-4 bg-green-50 border border-green-200 rounded-xl p-3">
              <p className="font-semibold text-green-700">
                Selected:
              </p>

              <p>{selectedLocation.location}</p>
            </div>
          )}
        </div>

        {/* Priority */}

        <div className="bg-white rounded-3xl shadow-lg p-5 mb-5 border">

          <h2 className="font-bold text-lg mb-4">
            🚨 Priority Level
          </h2>

          <div className="grid grid-cols-3 gap-3">

            <button
              onClick={() => setPriority("Low")}
              className={`py-3 rounded-xl font-semibold border transition-all
              ${
                priority === "Low"
                  ? "bg-green-700 text-white border-green-700"
                  : "bg-white"
              }`}
            >
              Low
            </button>

            <button
              onClick={() => setPriority("Medium")}
              className={`py-3 rounded-xl font-semibold border transition-all
              ${
                priority === "Medium"
                  ? "bg-yellow-500 text-white border-yellow-500"
                  : "bg-white"
              }`}
            >
              Medium
            </button>

            <button
              onClick={() => setPriority("High")}
              className={`py-3 rounded-xl font-semibold border transition-all
              ${
                priority === "High"
                  ? "bg-red-600 text-white border-red-600"
                  : "bg-white"
              }`}
            >
              High
            </button>

          </div>
        </div>

        {/* Submit */}

        <button
          onClick={handleSubmit}
          className="w-full bg-green-800 hover:bg-green-900 text-white py-4 rounded-2xl font-bold text-lg shadow-lg transition"
        >
          Submit & Notify Driver
        </button>

        {/* Status Timeline */}

        {requestCreated && (
          <div className="bg-white rounded-3xl shadow-lg p-6 mt-6 border">

            <h2 className="text-xl font-bold mb-6">
              📦 Request Status
            </h2>

            {steps.map((step, index) => (
              <div key={step}>

                <div className="flex items-start">

                  <div className="flex flex-col items-center">

                    <div
                      className={`w-10 h-10 rounded-full flex items-center justify-center font-bold
                      ${
                        index <= currentIndex
                          ? "bg-green-600 text-white"
                          : "bg-gray-200 text-gray-500"
                      }`}
                    >
                      {index <= currentIndex ? "✓" : index + 1}
                    </div>

                    {index !== steps.length - 1 && (
                      <div
                        className={`w-1 h-12
                        ${
                          index < currentIndex
                            ? "bg-green-600"
                            : "bg-gray-300"
                        }`}
                      />
                    )}
                  </div>

                  <div className="ml-4 pb-8">

                    <h3
                      className={`font-semibold
                      ${
                        index <= currentIndex
                          ? "text-green-700"
                          : "text-gray-500"
                      }`}
                    >
                      {step}
                    </h3>

                    {step === "Pending" && (
                      <p className="text-sm text-gray-500">
                        Request submitted successfully
                      </p>
                    )}

                    {step === "Accepted" && (
                      <p className="text-sm text-gray-500">
                        Driver accepted request
                      </p>
                    )}

                    {step === "Scheduled" && (
                      <p className="text-sm text-gray-500">
                        Pickup scheduled
                      </p>
                    )}

                    {step === "Arrived" && (
                      <p className="text-sm text-gray-500">
                        Driver arrived at location
                      </p>
                    )}

                    {step === "Completed" && (
                      <p className="text-sm text-gray-500">
                        Pickup completed successfully
                      </p>
                    )}

                  </div>

                </div>

              </div>
            ))}

          </div>
        )}

      </div>
    </div>
  );
}
